### Step 1: Define the Board Class

```python
class Board:
    def __init__(self):
        self.board = [
            [None] * 8 for _ in range(8)
        ]
        self.initialize_board()

    def initialize_board(self):
        pieces = ['B', 'W']  # Black and White
        for row in range(3):
            for col in range(0, 8, 2):
                if (row + col) % 2 == 1:
                    self.board[row][col] = Piece(row, col, pieces[0])
        for row in range(5, 8):
            for col in range(0, 8, 2):
                if (row + col) % 2 == 1:
                    self.board[row][col] = Piece(row, col, pieces[1])

    def get_piece(self, row, col):
        return self.board[row][col]

    def set_piece(self, row, col, piece):
        self.board[row][col] = piece

    def remove_piece(self, row, col):
        self.set_piece(row, col, None)

    def draw_board(self):
        for row in self.board:
            print(" ".join(str(piece) if piece else '.' for piece in row))
```

### Step 2: Define the Piece Class

```python
class Piece:
    def __init__(self, row, col, color):
        self.row = row
        self.col = col
        self.color = color
        self.is_king = False

    def __str__(self):
        return f"{self.color}K" if self.is_king else self.color

    def move(self, board, to_row, to_col):
        if abs(to_row - self.row) == 2:
            jump_piece = board.get_piece((to_row + self.row) // 2, (to_col + self.col) // 2)
            if jump_piece and jump_piece.color != self.color:
                board.remove_piece((to_row + self.row) // 2, (to_col + self.col) // 2)
        self.set_position(board, to_row, to_col)

    def set_position(self, board, row, col):
        board.remove_piece(self.row, self.col)
        self.row = row
        self.col = col
        board.set_piece(row, col, self)
        if (row == 0 and self.color == 'B') or (row == 7 and self.color == 'W'):
            self.make_king()

    def make_king(self):
        self.is_king = True
