### Step 3: Define the Game Manager Class

```python
class GameManager:
    def __init__(self):
        self.board = Board()
        self.current_player = 'B'

    def switch_turns(self):
        self.current_player = 'W' if self.current_player == 'B' else 'B'

    def is_valid_move(self, from_pos, to_pos):
        row_from, col_from = from_pos
        row_to, col_to = to_pos

        piece = self.board.get_piece(row_from, col_from)
        if piece and piece.color == self.current_player:
            return True
        return False

    def make_move(self, from_pos, to_pos):
        if not self.is_valid_move(from_pos, to_pos):
            raise ValueError("Invalid move")

        row_from, col_from = from_pos
        row_to, col_to = to_pos

        piece = self.board.get_piece(row_from, col_from)
        piece.move(self.board, row_to, col_to)

        self.switch_turns()

    def check_game_over(self):
        # Simple heuristic to determine if the game is over
        pieces_left = 0
        for row in range(8):
            for col in range(8):
                if self.board.get_piece(row, col) and self.board.get_piece(row, col).color == self.current_player:
                    pieces_left += 1
        return pieces_left == 0

    def play_game(self):
        print("Welcome to Checkers!")
        while True:
            self.board.draw_board()
            from_pos = input(f"{self.current_player}'s turn. Enter move (from-to): ").split('-')
            from_pos = (int(from_pos[0]) - 1, int(from_pos[1]) - 1)
            to_pos = input("Enter move (to): ").split('-')
            to_pos = (int(to_pos[0]) - 1, int(to_pos[1]) - 1)

            try:
                self.make_move(from_pos, to_pos)
            except ValueError as e:
                print(e)
                continue

            if self.check_game_over():
                print(f"Game over! {self.current_player} wins!")
                break
